INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES (0, 1, 100211, 0, "うん、これでいいと思う。\n傷はきれいに塞がったけど、\nまだどこか痛んだりするかな？", 10, 0, 1, 1200220005, 11, 20022);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("", "", 0, "", "", "", "", "", 1200220006, 91, 20022);
